package HashMapSolutions;

//Valid Anagram (LeetCode #242)
//The Problem: Given two strings, write a function to determine if one string is an anagram of the other (contains the exact same characters with the exact same frequencies).
//Constraints:
//        1 <= s.length, t.length <= 5 * 104
//s and t consist of lowercase English letters.

import java.util.HashMap;
import java.util.Map;

public class ValidAnagram {

    public static boolean checkAnagram(String f, String s) {
        // Fast-path guard clause
        if (f == null || s == null || f.length() != s.length()) {
            return false;
        }

        Map<Character, Integer> charCounts = new HashMap<>();

        // Step 1: Increment counts for the first string
        for (int i = 0; i < f.length(); i++) {
            char fChar = f.charAt(i);
            charCounts.put(fChar, charCounts.getOrDefault(fChar, 0) + 1);
        }

        // Step 2: Decrement counts for the second string
        for (int i = 0; i < s.length(); i++) {
            char sChar = s.charAt(i);

            // If the character doesn't exist in the first string, it can't be an anagram
            if (!charCounts.containsKey(sChar)) {
                return false;
            }

            int updatedCount = charCounts.get(sChar) - 1;
            if (updatedCount < 0) {
                return false; // Found more occurrences in 's' than in 'f'
            }

            charCounts.put(sChar, updatedCount);
        }

        // Step 3: Verify all counts dropped completely back to zero
        for (int count : charCounts.values()) {
            if (count != 0) {
                return false;
            }
        }

        return true;
    }

    public static void main(String[] args) {
        String f = "";
        String s = "";
        boolean isValidAnagram = checkAnagram(f, s);
        System.out.println(isValidAnagram);
    }
}
